SELECT c.id, u.id, 'french-b1-relations-et-conflits-speaking', 'speaking', 'Négocier une solution', 'Simule la résolution d’un petit conflit entre amis.', 102, 25, 'free', 12, true, 'Imagine un désaccord avec un ami sur un projet commun, et simule une conversation pour trouver un compromis, en exprimant tes émotions calmement.', NULL, '["Ça me dérange que...","Je suis triste que...","Peut-être qu’on pourrait...","Je comprends ton point de vue."]'::jsonb
FROM public.courses c
JOIN public.languages l ON l.id = c.language_id
JOIN public.levels lv ON lv.id = c.level_id
JOIN public.course_units u ON u.course_id = c.id AND u.slug = 'relations-et-conflits'
WHERE l.code = 'french' AND lv.code = 'B1'
ON CONFLICT (slug) DO UPDATE SET
  unit_id = EXCLUDED.unit_id, skill = EXCLUDED.skill, title = EXCLUDED.title, description = EXCLUDED.description,
  order_index = EXCLUDED.order_index, xp_reward = EXCLUDED.xp_reward, access_tier = EXCLUDED.access_tier,
  estimated_minutes = EXCLUDED.estimated_minutes, is_published = true,
  mission = EXCLUDED.mission, grammar_note = EXCLUDED.grammar_note, phrases = EXCLUDED.phrases;
