VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-a2-au-restaurant-writing'), 'dialogue_line', 0, 'Modèle', 'Samedi soir, j’ai dîné au restaurant « Le Petit Jardin ». J’ai commandé le poulet aux légumes, c’était délicieux. Le service était un peu lent, mais dans l’ensemble, je recommande ce restaurant.', 'El sábado por la noche cené en el restaurante "Le Petit Jardin". Pedí pollo con verduras, estaba delicioso. El servicio fue un poco lento, pero en general, recomiendo este restaurante.');
