INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-a2-les-voyages-et-les-vacances-writing'), 'dialogue_line', 0, 'Modèle', 'Chère maman, je suis à Nice avec la famille Lambert ! On s’est baignés tous les jours et on a visité la vieille ville. La vue depuis l’hôtel est magnifique. C’était un voyage inoubliable. À bientôt, Camila.', 'Querida mamá, ¡estoy en Niza con la familia Lambert! Nos bañamos todos los días y visitamos el casco antiguo. La vista desde el hotel es magnífica. Fue un viaje inolvidable. Hasta pronto, Camila.');
