INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-a2-le-logement-writing'), 'dialogue_line', 0, 'Modèle', 'À louer : appartement meublé avec deux chambres, un salon lumineux et une cuisine séparée. Situé dans un quartier calme, près du centre-ville. Loyer : cinq cents euros par mois, charges comprises.', 'Se alquila: apartamento amueblado con dos habitaciones, un salón luminoso y una cocina separada. Ubicado en un barrio tranquilo, cerca del centro. Alquiler: quinientos euros al mes, gastos incluidos.');
