VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-a2-les-loisirs-et-les-medias-dialogue'), 'dialogue_line', 0, 'Karim', 'Je n’aime jamais les documentaires normalement, mais celui-là était génial !', 'Normalmente nunca me gustan los documentales, ¡pero ese estuvo genial!');
