INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-identite-et-parcours-personnel-writing'), 'dialogue_line', 0, 'Modèle', 'Avant, j’étais quelqu’un de très timide. Un jour, j’ai décidé de sortir de ma zone de confort et de participer à un projet nouveau. Depuis, j’ai gagné en confiance. Aujourd’hui, je suis une personne plus sûre d’elle-même.', 'Antes era alguien muy tímido. Un día decidí salir de mi zona de confort y participar en un nuevo proyecto. Desde entonces, he ganado confianza. Hoy soy una persona más segura de sí misma.');
