INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-identite-et-parcours-personnel-dialogue'), 'dialogue_line', 0, 'Mme Lambert', 'Tu as tellement changé depuis ton arrivée, Camila. Je suis fière de toi.', 'Has cambiado tanto desde que llegaste, Camila. Estoy orgullosa de ti.');
