INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-monde-du-travail-writing'), 'dialogue_line', 0, 'Modèle', 'Madame, Monsieur, je me permets de vous écrire pour postuler au stage d’été à la bibliothèque. Je suis passionné par la lecture et je voudrais mettre mes compétences organisationnelles à votre service. Dans l’attente de votre réponse, je vous prie d’agréer mes salutations distinguées.', 'Señora, señor, me permito escribirle para postular a la pasantía de verano en la biblioteca. Me apasiona la lectura y quisiera poner mis habilidades organizativas a su servicio. En espera de su respuesta, le saluda atentamente.');
