INSERT INTO public.lesson_sections (lesson_id, type, order_index, line)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-voyages-et-interculturalite-dialogue'), 'intro', 0, 'Après le cours, Léa et Karim discutent avec Camila de son exposé.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-voyages-et-interculturalite-dialogue'), 'dialogue_line', 0, 'Léa', 'Ton exposé était vraiment intéressant, Camila !', '¡Tu exposición fue realmente interesante, Camila!');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-voyages-et-interculturalite-dialogue'), 'dialogue_line', 1, 'Karim', 'Oui, j’ai appris plein de choses sur ton pays.', 'Sí, aprendí muchas cosas sobre tu país.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
