VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-relations-et-conflits-vocabulary'), 'vocabulary_item', 4, 'ça me dérange que', 'me molesta que', 'Ça me dérange que tu sois toujours en retard.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, line)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-relations-et-conflits-dialogue'), 'intro', 0, 'Après avoir terminé leur exposé avec succès, Camila et Léa parlent de ce qu’elles ont appris.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-relations-et-conflits-dialogue'), 'dialogue_line', 0, 'Camila', 'Je suis contente qu’on ait pu parler calmement de notre désaccord.', 'Estoy contenta de que hayamos podido hablar con calma de nuestro desacuerdo.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-relations-et-conflits-dialogue'), 'dialogue_line', 1, 'Léa', 'Moi aussi. Je pense que notre amitié est encore plus forte maintenant.', 'Yo también. Creo que nuestra amistad es aún más fuerte ahora.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-relations-et-conflits-dialogue'), 'dialogue_line', 2, 'Camila', 'Même si on n’est pas toujours d’accord, on sait qu’on peut se parler honnêtement.', 'Aunque no siempre estemos de acuerdo, sabemos que podemos hablar honestamente.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b1-relations-et-conflits-dialogue'), 'dialogue_line', 3, 'Léa', 'Exactement, et c’est ça, une vraie amitié.', 'Exactamente, y eso es una verdadera amistad.');

