-- ---------------------------------------------------------------------
-- 9. Verification (runs inside this same transaction, right before COMMIT,
--    so it reflects every insert/update above): confirms the expected counts.
-- ---------------------------------------------------------------------
SELECT lv.code AS level, count(DISTINCT cu.id) AS units, count(DISTINCT cl.id) AS activities
FROM public.levels lv
JOIN public.courses c ON c.level_id = lv.id
JOIN public.languages l ON l.id = c.language_id AND l.code = 'french'
LEFT JOIN public.course_units cu ON cu.course_id = c.id
LEFT JOIN public.course_lessons cl ON cl.course_id = c.id
WHERE lv.code IN ('A1', 'A2', 'B1')
GROUP BY lv.code
ORDER BY lv.code;

-- Expected: A1 = 12 units / 84 activities (untouched), A2 = 10 / 70, B1 = 10 / 70.

COMMIT;

